action_json:
{"action": "write_file", "file_path": "nginx.conf", "content": "server {
    listen 80;
    server_name example.com;
    location / {
        proxy_pass http://localhost:3000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
    }
}", "explanation": "Creating NGINX reverse proxy configuration"}

{"action": "write_file", "file_path": "variables.tf", "content": "variable "region" {
  description = "AWS region"
  type = string
  default = "us-east-1"
}

variable "instance_type" {
  description = "EC2 instance type"
  type = string
  default = "t3.micro"
}", "explanation": "Creating Terraform variables file"}

{"action": "write_file", "file_path": "Jenkinsfile", "content": "pipeline {
  agent any
  stages {
    stage('Build') {
      steps { sh 'npm ci' }
    }
    stage('Test') {
      steps { sh 'npm test' }
    }
    stage('Deploy') {
      steps { sh 'npm run deploy' }
    }
  }
}", "explanation": "Creating Jenkinsfile pipeline"}

{"action": "write_file", "file_path": "main.tf", "content": "provider "aws" {
  region = var.region
}

resource "aws_instance" "app" {
  ami           = "ami-0c55b159cbfafe1f0"
  instance_type = var.instance_type
  tags = {
    Name = "myapp-server"
  }
}", "explanation": "Creating Terraform main.tf for AWS EC2 instance"}

{"action": "write_file", "file_path": "s3.tf", "content": "resource "aws_s3_bucket" "app_storage" {
  bucket = "myapp-storage-${var.environment}"
  tags = {
    Name = "App Storage"
  }
}", "explanation": "Creating Terraform S3 bucket configuration"}

{"action": "write_file", "file_path": "outputs.tf", "content": "output "instance_id" {
  value = aws_instance.app.id
}
output "public_ip" {
  value = aws_instance.app.public_ip
}", "explanation": "Creating Terraform outputs file"}

{"action": "write_file", "file_path": "backend.tf", "content": "terraform {
  backend "s3" {
    bucket = "myapp-terraform-state"
    key = "prod/terraform.tfstate"
    region = "us-east-1"
    encrypt = true
  }
}", "explanation": "Creating Terraform S3 backend configuration"}

{"action": "write_file", "file_path": "vpc.tf", "content": "resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "myapp-vpc"
  }
}", "explanation": "Creating Terraform VPC configuration"}

{"action": "write_file", "file_path": "ecs.tf", "content": "resource "aws_ecs_task_definition" "app" {
  family = "myapp"
  network_mode = "awsvpc"
  requires_compatibilities = ["FARGATE"]
  cpu = 256
  memory = 512
}", "explanation": "Creating Terraform ECS task definition"}

{"action": "write_file", "file_path": "iam.tf", "content": "resource "aws_iam_role" "app" {
  name = "myapp-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "ec2.amazonaws.com" }
    }]
  })
}", "explanation": "Creating Terraform IAM role configuration"}

{"action": "write_file", "file_path": "security-group.tf", "content": "resource "aws_security_group" "app" {
  name = "myapp-sg"
  vpc_id = aws_vpc.main.id
  ingress {
    from_port = 80
    to_port = 80
    protocol = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
  egress {
    from_port = 0
    to_port = 0
    protocol = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}", "explanation": "Creating Terraform security group configuration"}

{"action": "write_file", "file_path": "alb.tf", "content": "resource "aws_lb" "app" {
  name = "myapp-alb"
  internal = false
  load_balancer_type = "application"
  subnets = aws_subnet.public[*].id
}", "explanation": "Creating Terraform ALB configuration"}

{"action": "write_file", "file_path": "cloudwatch.tf", "content": "resource "aws_cloudwatch_metric_alarm" "cpu" {
  alarm_name = "myapp-high-cpu"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods = 2
  metric_name = "CPUUtilization"
  namespace = "AWS/EC2"
  period = 300
  statistic = "Average"
  threshold = 80
}", "explanation": "Creating Terraform CloudWatch alarm"}

{"action": "write_file", "file_path": "dns.tf", "content": "resource "aws_route53_record" "app" {
  zone_id = data.aws_route53_zone.main.zone_id
  name = "app.example.com"
  type = "A"
  alias {
    name = aws_lb.app.dns_name
    zone_id = aws_lb.app.zone_id
    evaluate_target_health = true
  }
}", "explanation": "Creating Terraform Route53 DNS record"}

{"action": "write_file", "file_path": "ecr.tf", "content": "resource "aws_ecr_repository" "app" {
  name = "myapp"
  image_tag_mutability = "MUTABLE"
  image_scanning_configuration {
    scan_on_push = true
  }
}", "explanation": "Creating Terraform ECR repository"}

{"action": "write_file", "file_path": "lambda.tf", "content": "resource "aws_lambda_function" "app" {
  filename = "lambda.zip"
  function_name = "myapp-handler"
  role = aws_iam_role.lambda.arn
  handler = "index.handler"
  runtime = "nodejs20.x"
  timeout = 30
}", "explanation": "Creating Terraform Lambda function configuration"}

{"action": "write_file", "file_path": "sqs.tf", "content": "resource "aws_sqs_queue" "app" {
  name = "myapp-queue"
  delay_seconds = 0
  message_retention_seconds = 86400
  receive_wait_time_seconds = 10
}", "explanation": "Creating Terraform SQS queue"}

{"action": "write_file", "file_path": "logrotate.conf", "content": "/var/log/myapp/*.log {
    daily
    missingok
    rotate 14
    compress
    notifempty
}", "explanation": "Creating logrotate configuration"}

{"action": "write_file", "file_path": "dynamodb.tf", "content": "resource "aws_dynamodb_table" "app" {
  name = "myapp-table"
  billing_mode = "PAY_PER_REQUEST"
  hash_key = "pk"
  range_key = "sk"
  attribute {
    name = "pk"
    type = "S"
  }
  attribute {
    name = "sk"
    type = "S"
  }
}", "explanation": "Creating Terraform DynamoDB table"}

{"action": "write_file", "file_path": ".eslintrc.json", "content": "{
  "env": { "node": true },
  "extends": ["eslint:recommended"],
  "rules": { "no-unused-vars": "warn" }
}", "explanation": "Creating ESLint configuration file"}

{"action": "write_file", "file_path": "sns.tf", "content": "resource "aws_sns_topic" "alerts" {
  name = "myapp-alerts"
}
resource "aws_sns_topic_subscription" "email" {
  topic_arn = aws_sns_topic.alerts.arn
  protocol = "email"
  endpoint = "devops@example.com"
}", "explanation": "Creating Terraform SNS topic for alerts"}

{"action": "write_file", "file_path": "cloudfront.tf", "content": "resource "aws_cloudfront_distribution" "app" {
  origin {
    domain_name = aws_s3_bucket.app.bucket_regional_domain_name
    origin_id = "s3-origin"
  }
  enabled = true
  default_root_object = "index.html"
  default_cache_behavior {
    allowed_methods = ["GET", "HEAD"]
    cached_methods = ["GET", "HEAD"]
    target_origin_id = "s3-origin"
    viewer_protocol_policy = "redirect-to-https"
    forwarded_values {
      query_string = false
      cookies { forward = "none" }
    }
  }
  restrictions {
    geo_restriction { restriction_type = "none" }
  }
  viewer_certificate {
    cloudfront_default_certificate = true
  }
}", "explanation": "Creating Terraform CloudFront distribution"}

{"action": "write_file", "file_path": "tsconfig.json", "content": "{
  "compilerOptions": {
    "target": "ES2022",
    "module": "NodeNext",
    "outDir": "./dist",
    "strict": true,
    "esModuleInterop": true
  },
  "include": ["src/**/*"]
}", "explanation": "Creating TypeScript configuration file"}

{"action": "write_file", "file_path": "elasticache.tf", "content": "resource "aws_elasticache_cluster" "app" {
  cluster_id = "myapp-cache"
  engine = "redis"
  node_type = "cache.t3.micro"
  num_cache_nodes = 1
  port = 6379
}", "explanation": "Creating Terraform ElastiCache Redis configuration"}

{"action": "write_file", "file_path": "package.json", "content": "{
  "name": "myapp-service",
  "version": "1.0.0",
  "scripts": {
    "start": "node src/index.js",
    "test": "jest --coverage"
  },
  "dependencies": {
    "express": "^4.18.2"
  }
}", "explanation": "Creating package.json for Node.js microservice"}

{"action": "write_file", "file_path": "eks.tf", "content": "module "eks" {
  source = "terraform-aws-modules/eks/aws"
  version = "~> 19.0"
  cluster_name = "myapp-cluster"
  cluster_version = "1.28"
  vpc_id = aws_vpc.main.id
  subnet_ids = aws_subnet.private[*].id
}", "explanation": "Creating Terraform EKS cluster configuration"}

{"action": "write_file", "file_path": "waf.tf", "content": "resource "aws_wafv2_web_acl" "app" {
  name = "myapp-waf"
  scope = "REGIONAL"
  default_action { allow {} }
  visibility_config {
    sampled_requests_enabled = true
    cloudwatch_metrics_enabled = true
    metric_name = "myapp-waf"
  }
}", "explanation": "Creating Terraform WAF configuration"}

{"action": "write_file", "file_path": "asg.tf", "content": "resource "aws_autoscaling_group" "app" {
  name = "myapp-asg"
  min_size = 2
  max_size = 10
  desired_capacity = 3
  launch_template {
    id = aws_launch_template.app.id
    version = "$Latest"
  }
}", "explanation": "Creating Terraform Auto Scaling Group"}

{"action": "write_file", "file_path": "cloudtrail.tf", "content": "resource "aws_cloudtrail" "main" {
  name = "myapp-trail"
  s3_bucket_name = aws_s3_bucket.trail.id
  include_global_service_events = true
  is_multi_region_trail = true
  enable_logging = true
}", "explanation": "Creating Terraform CloudTrail audit logging"}

{"action": "write_file", "file_path": "apigateway.tf", "content": "resource "aws_apigatewayv2_api" "app" {
  name = "myapp-api"
  protocol_type = "HTTP"
}", "explanation": "Creating Terraform API Gateway configuration"}

{"action": "write_file", "file_path": "fluentd.conf", "content": "<source>
  @type forward
  port 24224
</source>
<match app.**>
  @type elasticsearch
  host elasticsearch
  port 9200
  index_name myapp-logs
</match>", "explanation": "Creating Fluentd log aggregation configuration"}

{"action": "write_file", "file_path": "grafana/dashboard.json", "content": "{
  "dashboard": {
    "title": "Application Metrics",
    "panels": [
      { "title": "Request Rate", "type": "graph" },
      { "title": "Error Rate", "type": "graph" }
    ]
  }
}", "explanation": "Creating Grafana dashboard configuration"}

{"action": "write_file", "file_path": "cognito.tf", "content": "resource "aws_cognito_user_pool" "app" {
  name = "myapp-users"
  auto_verified_attributes = ["email"]
  password_policy {
    minimum_length = 8
    require_uppercase = true
    require_numbers = true
  }
}", "explanation": "Creating Terraform Cognito user pool"}

{"action": "write_file", "file_path": "consul.hcl", "content": "datacenter = "dc1"
server = true
bootstrap_expect = 3
client_addr = "0.0.0.0"
ui_config {
  enabled = true
}", "explanation": "Creating Consul service mesh configuration"}

{"action": "write_file", "file_path": "index.ts", "content": "import * as aws from "@pulumi/aws";
const bucket = new aws.s3.Bucket("myapp-bucket");
const instance = new aws.ec2.Instance("myapp-server", {
  instanceType: "t3.micro",
  ami: "ami-0c55b159cbfafe1f0",
});
export const bucketName = bucket.id;", "explanation": "Creating Pulumi infrastructure as code"}

{"action": "write_file", "file_path": "codepipeline.tf", "content": "resource "aws_codepipeline" "app" {
  name = "myapp-pipeline"
  role_arn = aws_iam_role.codepipeline.arn
  artifact_store {
    location = aws_s3_bucket.artifacts.bucket
    type = "S3"
  }
  stage {
    name = "Source"
    action {
      name = "Source"
      category = "Source"
      owner = "AWS"
      provider = "CodeStarSourceConnection"
      version = "1"
      output_artifacts = ["source"]
    }
  }
}", "explanation": "Creating Terraform CodePipeline configuration"}

{"action": "write_file", "file_path": "stepfunctions.tf", "content": "resource "aws_sfn_state_machine" "app" {
  name = "myapp-workflow"
  role_arn = aws_iam_role.sfn.arn
  definition = jsonencode({
    StartAt = "ProcessInput"
    States = {
      ProcessInput = {
        Type = "Task"
        Resource = aws_lambda_function.process.arn
        End = true
      }
    }
  })
}", "explanation": "Creating Terraform Step Functions state machine"}

{"action": "write_file", "file_path": "elasticbeanstalk.tf", "content": "resource "aws_elastic_beanstalk_application" "app" {
  name = "myapp"
}
resource "aws_elastic_beanstalk_environment" "app" {
  name = "myapp-env"
  application = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v6.0.0 running Node.js 20"
}", "explanation": "Creating Terraform Elastic Beanstalk configuration"}

{"action": "write_file", "file_path": "dashboard.tf", "content": "resource "aws_cloudwatch_dashboard" "app" {
  dashboard_name = "myapp-dashboard"
  dashboard_body = jsonencode({
    widgets = [
      {
        type = "metric"
        properties = {
          metrics = [["AWS/EC2", "CPUUtilization"]]
          title = "CPU Utilization"
        }
      }
    ]
  })
}", "explanation": "Creating Terraform CloudWatch dashboard"}

{"action": "write_file", "file_path": "kms.tf", "content": "resource "aws_kms_key" "app" {
  description = "KMS key for myapp encryption"
  deletion_window_in_days = 7
  enable_key_rotation = true
}

resource "aws_kms_alias" "app" {
  name = "alias/myapp-key"
  target_key_id = aws_kms_key.app.key_id
}", "explanation": "Creating Terraform KMS key for encryption"}

{"action": "write_file", "file_path": "secrets-manager.tf", "content": "resource "aws_secretsmanager_secret" "app" {
  name = "myapp/credentials"
  description = "Application credentials"
}

resource "aws_secretsmanager_secret_version" "app" {
  secret_id = aws_secretsmanager_secret.app.id
  secret_string = jsonencode({
    db_password = var.db_password
    api_key = var.api_key
  })
}", "explanation": "Creating Terraform Secrets Manager configuration"}

{"action": "write_file", "file_path": "eventbridge.tf", "content": "resource "aws_cloudwatch_event_rule" "app" {
  name = "myapp-schedule"
  schedule_expression = "rate(5 minutes)"
}

resource "aws_cloudwatch_event_target" "app" {
  rule = aws_cloudwatch_event_rule.app.name
  arn = aws_lambda_function.app.arn
}", "explanation": "Creating Terraform EventBridge scheduled rule"}

{"action": "write_file", "file_path": "waf-ipset.tf", "content": "resource "aws_wafv2_ip_set" "blocklist" {
  name = "myapp-blocklist"
  scope = "REGIONAL"
  ip_address_version = "IPV4"
  addresses = ["192.0.2.0/24", "198.51.100.0/24"]
}", "explanation": "Creating Terraform WAF IP set for blocking"}

{"action": "write_file", "file_path": "logs.tf", "content": "resource "aws_cloudwatch_log_group" "app" {
  name = "/ecs/myapp"
  retention_in_days = 30
  tags = {
    Application = "myapp"
  }
}", "explanation": "Creating Terraform CloudWatch log group"}

{"action": "write_file", "file_path": "ssm.tf", "content": "resource "aws_ssm_parameter" "db_host" {
  name = "/myapp/db_host"
  type = "String"
  value = aws_db_instance.main.endpoint
}

resource "aws_ssm_parameter" "db_password" {
  name = "/myapp/db_password"
  type = "SecureString"
  value = var.db_password
}", "explanation": "Creating Terraform SSM parameter store entries"}

{"action": "write_file", "file_path": "efs.tf", "content": "resource "aws_efs_file_system" "app" {
  creation_token = "myapp-efs"
  performance_mode = "generalPurpose"
  encrypted = true
  tags = {
    Name = "myapp-efs"
  }
}", "explanation": "Creating Terraform EFS file system"}

{"action": "write_file", "file_path": "nat.tf", "content": "resource "aws_eip" "nat" {
  domain = "vpc"
}

resource "aws_nat_gateway" "main" {
  allocation_id = aws_eip.nat.id
  subnet_id = aws_subnet.public[0].id
  tags = {
    Name = "myapp-nat"
  }
}", "explanation": "Creating Terraform NAT Gateway configuration"}

{"action": "write_file", "file_path": "igw.tf", "content": "resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "myapp-igw"
  }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}", "explanation": "Creating Terraform Internet Gateway and route table"}

{"action": "write_file", "file_path": "transit-gw.tf", "content": "resource "aws_ec2_transit_gateway" "main" {
  description = "Main Transit Gateway"
  auto_accept_shared_attachments = "enable"
  tags = {
    Name = "myapp-tgw"
  }
}", "explanation": "Creating Terraform Transit Gateway configuration"}

{"action": "write_file", "file_path": "acm.tf", "content": "resource "aws_acm_certificate" "app" {
  domain_name = "app.example.com"
  subject_alternative_names = ["*.app.example.com"]
  validation_method = "DNS"
  lifecycle {
    create_before_destroy = true
  }
}", "explanation": "Creating Terraform ACM SSL certificate"}
